<template><div style="padding:20px"><el-card><template #header><span>每日签到</span></template><div style="text-align:center;padding:40px"><el-button type="primary" size="large" @click="handleCheckin" :loading="loading">签到</el-button><p style="margin-top:20px" v-if="todayChecked">今日已签到</p></div></el-card></div></template>
<script setup>import {ref,onMounted} from "vue";import {ElMessage} from "element-plus";import axios from "axios";const loading=ref(false);const todayChecked=ref(false);const handleCheckin=async()=>{loading.value=true;try{await axios.post("/api/v1/checkin/daily");todayChecked.value=true;ElMessage.success("签到成功")}catch(e){ElMessage.error("签到失败")}finally{loading.value=false}};const loadStatus=async()=>{try{const res=await axios.get("/api/v1/checkin/status");todayChecked.value=res.data.today_checked}catch(e){}};onMounted(loadStatus)</script>
